import { Injectable, inject } from '@angular/core';
import { Observable, of, throwError } from 'rxjs';
import { catchError, switchMap } from 'rxjs/operators';
import { AuthService } from './auth.service';
import {
  LOCAL_STORAGE_KEY_ACCESS_TOKEN,
  LOCAL_STORAGE_KEY_REFRESH_TOKEN,
  LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
  LOCAL_STORAGE_KEY_USER_SESSION,
} from '../models';
import { isDefined, isString } from '../../shared/utils';
import { UserSessionResponse } from '../../api';
import { UserSessionService } from './user-session.service';
import { LocalStorageService } from '../../shared/services/local-storage.service';

@Injectable({
  providedIn: 'root',
})
export class AuthTokenManagerService {
  private readonly authService = inject(AuthService);
  private readonly userSessionService = inject(UserSessionService);
  private readonly localStorageService = inject(LocalStorageService);

  // private readonly TOKEN_EXPIRY_BUFFER = 60000*59+55000; // 1 minute before expiry
  private readonly TOKEN_EXPIRY_BUFFER = 60000; // 1 minute before expiry
  private readonly TOKEN_EXPIRY_TIME = 3600000; // 1 hour in milliseconds
  private refreshTokenTimeout: ReturnType<typeof setTimeout> | null = null;

  constructor() {
    this.scheduleTokenRefresh();
  }

  // Store tokens in localStorage
  storeTokens(response: UserSessionResponse): void {
    this.localStorageService.setItem(
      LOCAL_STORAGE_KEY_ACCESS_TOKEN,
      response.accessToken,
      undefined,
      true,
    );
    this.localStorageService.setItem(
      LOCAL_STORAGE_KEY_REFRESH_TOKEN,
      response.refreshToken,
      undefined,
      true,
    );
    this.localStorageService.setItem(
      LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
      (Date.now() + this.TOKEN_EXPIRY_TIME).toString(),
      undefined,
      true,
    );
    // Use LocalStorageService for API-scoped USER_SESSION key to maintain proper namespacing
    this.localStorageService.setItem(
      LOCAL_STORAGE_KEY_USER_SESSION,
      JSON.stringify(response.users ?? []),
      undefined,
      true,
    );
    // CRITICAL: Sync UserSessionService signal with new sessions from API
    // This ensures context-selection wizard has access to accounts immediately
    if (isDefined(response.users) && response.users.length > 0) {
      this.userSessionService.setUserSessions(response.users);
    }
    this.scheduleTokenRefresh();
  }

  // Get access token from localStForage
  getAccessToken(): string | null {
    return this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_ACCESS_TOKEN,
      true,
    );
  }

  // Get refresh token from localStorage
  getRefreshToken(): string | null {
    return this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_REFRESH_TOKEN,
      true,
    );
  }

  getTokenExpiry(): string | null {
    const expiry = this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
      true,
    );
    if (!isString(expiry)) return null;

    const expiryTimestamp = Number.parseInt(expiry, 10);
    if (Number.isNaN(expiryTimestamp)) return null;

    return new Date(expiryTimestamp).toISOString();
  }

  // Check if the token is expired
  isTokenExpired(): boolean {
    const expiry = this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
      true,
    );
    if (!isString(expiry)) return true;

    const expiryTimestamp = Number.parseInt(expiry, 10);
    return Number.isNaN(expiryTimestamp) || Date.now() > expiryTimestamp;
  }

  // Clear tokens from localStorage
  clearTokens(): void {
    this.localStorageService.removeItem(LOCAL_STORAGE_KEY_ACCESS_TOKEN, true);
    this.localStorageService.removeItem(LOCAL_STORAGE_KEY_REFRESH_TOKEN, true);
    this.localStorageService.removeItem(LOCAL_STORAGE_KEY_TOKEN_EXPIRY, true);
    if (isDefined(this.refreshTokenTimeout)) {
      clearTimeout(this.refreshTokenTimeout);
      this.refreshTokenTimeout = null;
    }
  }

  // Schedule token refresh before expiry
  private scheduleTokenRefresh(): void {
    if (this.isTokenExpired()) {
      this.clearTokens();
      return;
    }

    const expiry = this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
      true,
    );
    if (!isString(expiry)) {
      this.clearTokens();
      return;
    }

    const expiryTimestamp = Number.parseInt(expiry, 10);
    if (Number.isNaN(expiryTimestamp)) {
      this.clearTokens();
      return;
    }

    const timeout = Math.max(
      0,
      expiryTimestamp - Date.now() - this.TOKEN_EXPIRY_BUFFER,
    );
    if (isDefined(this.refreshTokenTimeout)) {
      clearTimeout(this.refreshTokenTimeout);
    }

    this.refreshTokenTimeout = setTimeout(() => {
      this.refreshToken().subscribe();
    }, timeout);
  }

  // Refresh the token
  private refreshToken(): Observable<UserSessionResponse> {
    const refreshToken = this.getRefreshToken();
    if (!isString(refreshToken)) {
      this.clearTokens();
      return throwError(() => 'No refresh token available');
    }

    return this.authService.refreshToken(refreshToken).pipe(
      switchMap(
        (response: UserSessionResponse): Observable<UserSessionResponse> => {
          this.storeTokens(response);
          return of(response);
        },
      ),
      catchError((error) => {
        this.clearTokens();
        return throwError(() => error);
      }),
    );
  }
}
