import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiUrlService } from './api-url.service';
import { isString } from '../../shared/utils';
import { LOCAL_STORAGE_KEY_TOKEN_EXPIRY } from '../models';
import { LocalStorageService } from '../../shared/services/local-storage.service';
import { UserSessionResponse } from '../../api';

@Injectable({
  providedIn: 'root',
})
export class AuthService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly localStorageService = inject(LocalStorageService);

  login(username: string, password: string): Observable<UserSessionResponse> {
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();
    return this.http.post<UserSessionResponse>(`${currentApiUrl}/auth/signin`, {
      username,
      password,
    });
  }

  loginWithToken(token: string): Observable<UserSessionResponse> {
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();
    return this.http.post<UserSessionResponse>(`${currentApiUrl}/auth/signin`, {
      token,
    });
  }

  refreshToken(refreshToken: string): Observable<UserSessionResponse> {
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();
    return this.http.post<UserSessionResponse>(
      `${currentApiUrl}/auth/refresh`,
      {
        refreshToken,
      },
    );
  }

  isAuthenticated(): boolean {
    const expiry =
      this.localStorageService.getItem<string>(
        LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
        true,
      ) ?? localStorage.getItem(LOCAL_STORAGE_KEY_TOKEN_EXPIRY);

    if (!isString(expiry)) {
      return false;
    }

    const expiryValue = Number.parseInt(expiry, 10);
    if (Number.isNaN(expiryValue)) {
      return false;
    }

    return Date.now() < expiryValue;
  }
}
